sort(
  1 / (
    avg by (provider) (
      (
        1 / avg by (provider, source_region) (
          quantile_over_time(0.95, 
            (response_latency_seconds{blockchain="TON", response_status="success"} > 0)[$__range:$__interval]
          )
        )
      )
      *
      (
        (
          sum by (provider, source_region) (count_over_time((response_latency_seconds{blockchain="TON", response_status="success"} > 0)[$__range:$__interval]))
          /
          sum by (provider, source_region) (count_over_time((response_latency_seconds{blockchain="TON"} > 0)[$__range:$__interval]))
        )
        *
        (
          sum by (provider, source_region) (count_over_time((response_latency_seconds{blockchain="TON", response_status="success"} > 0)[$__range:$__interval]))
          /
          sum by (provider, source_region) (count_over_time((response_latency_seconds{blockchain="TON"} > 0)[$__range:$__interval]))
        )
        *
        (
          sum by (provider, source_region) (count_over_time((response_latency_seconds{blockchain="TON", response_status="success"} > 0)[$__range:$__interval]))
          /
          sum by (provider, source_region) (count_over_time((response_latency_seconds{blockchain="TON"} > 0)[$__range:$__interval]))
        )
      )
    )
  )
)

avg by (provider, api_method, source_region) (
